public:
  Node *dfs(Node *nd, unordered_map<Node *, Node *> &nodeMap) {
    if (nd == nullptr) {
      return nullptr;
    }

    auto it = nodeMap.find(nd);
    if (it != nodeMap.end()) {
      return it->second;
    }

    Node *newNode = new Node(nd->val);
    nodeMap.insert({nd, newNode});

    vector<Node *> &vec = newNode->neighbors;
    vec.reserve(nd->neighbors.size());

    for (const auto &neighour : nd->neighbors) {
      vec.push_back(dfs(neighour, nodeMap));
    }

    return newNode;
  }

  Node *cloneGraph(Node *nd) {
    unordered_map<Node *, Node *> nodeMap;
    return dfs(nd, nodeMap);
  }
};

