class Solution {
  enum State { EMPTY, FRESH, ROTTEN };

public:
  int orangesRotting(vector<vector<int>> &grid) {
    queue<pair<int, int>> q;
    int fresh = 0;
    for (int r = 0; r < grid.size(); r++) {
      for (int c = 0; c < grid[0].size(); c++) {
        if (grid[r][c] == 1) {
          fresh++;
        } else if (grid[r][c] == 2) {
          q.push({r, c});
        }
      }
    }

    if (q.size() == 0) {
      return (fresh == 0) ? 0 : -1;
    }

    int mins = 0;

    while (!q.empty()) {

      int size = q.size();
      for (int i = 0; i < size; i++) {
        auto &rc = q.front();
        int r = rc.first;
        int c = rc.second;
        q.pop();

        if (r > 0 && grid[r - 1][c] == 1) {
          grid[r - 1][c] = 2;
          fresh--;
          q.push({r - 1, c});
        }
        if (r < grid.size() - 1 && grid[r + 1][c] == 1) {
          grid[r + 1][c] = 2;
          fresh--;
          q.push({r + 1, c});
        }
        if (c > 0 && grid[r][c - 1] == 1) {
          grid[r][c - 1] = 2;
          fresh--;
          q.push({r, c - 1});
        }
        if (c < grid[r].size() - 1 && grid[r][c + 1] == 1) {
          grid[r][c + 1] = 2;
          fresh--;
          q.push({r, c + 1});
        }
      }
      if (q.size() > 0) {
        mins++;
      }
    }
    return (fresh == 0) ? mins : -1;
  }
};

