public:
  ListNode *removeNthFromEnd(ListNode *head, int n) {
    int i = 0;
    if (head == nullptr)
      return nullptr;
    ListNode dummy;
    dummy.val = 0;
    dummy.next = head;

    ListNode *front = &dummy;
    while (front != nullptr && i <= n) {
      front = front->next;
      i++;
    }
    ListNode *nd = &dummy;
    while (front != nullptr) {
      front = front->next;
      nd = nd->next;
    }

    nd->next = (nd->next) ? nd->next->next : nullptr;

    return dummy.next;
  }
};

