        formed++;
      }

      while (l <= r && formed == required) {
        c = s[l];
        if (ans[0] == -1 || r - l + 1 < ans[0]) {
          ans[0] = r - l + 1;
          ans[1] = l;
          ans[2] = r;
        }

        windowCounts[c]--;
        if (dictT.count(c) && windowCounts[c] < dictT[c]) {
          formed--;
        }
        l++;
      }
      r++;
    }

    return ans[0] == -1 ? "" : s.substr(ans[1], ans[0]);
  }
};

