  bool isValid(string s) {
    stack<char> st;
    for (auto ch : s) {
      if (ch == '(' || ch == '{' || ch == '[') {
        st.push(ch);
      } else if (ch == ')' || ch == '}' || ch == ']') {
        if (st.empty())
          return false; // No matching opening bracket
        char ctop = st.top();
        st.pop();
        if ((ch == ')' && ctop != '(') || (ch == '}' && ctop != '{') ||
            (ch == ']' && ctop != '[')) {
          return false;
        }
      }
    }
    return st.empty(); // All brackets should be matched
  }
};

