    int r = s.size() - 1;
    while (l < r) {
      while (l < r && !isalnum(s[l])) {
        l++;
      }
      while (l < r && !isalnum(s[r])) {
        r--;
      }
      if (tolower(s[l]) == tolower(s[r])) {
        l++;
        r--;
      } else {
        break;
      }
    }
    return l >= r;
  }
};

